const input = $('Webhook Landing').first().json.body;

// ===== MAPEO INGRESO → ID BITRIX =====
const mapaIngresos = {
  'Menos de S/3,000': 2379,
  'Entre S/3,000 y S/4,000': 2381,
  'Entre S/4,000 y S/6,000': 2383,
  'Entre S/6,000 y S/9,000': 2385,
  'Entre S/9,000 y S/12,000': 2387,
  'Entre S/12,000 y S/15,000': 2389,
  'Entre S/15,000 y S/20,000': 3479,
  'Más de S/20,000': 3481,
  'S/3,000 - S/5,000': 2383,
  'S/5,000 - S/8,000': 2385,
  'S/8,000 - S/12,000': 2387,
  'S/12,000 - S/20,000': 3479
};

// ===== MAPEO INICIAL → ID BITRIX =====
const mapaInicial = {
  'Menos de S/25,000': 2391,
  'Entre S/25,000 y S/35,000': 2393,
  'Entre S/35,000 y S/50,000': 2395,
  'Entre S/50,000 y S/70,000': 2399,
  'Entre S/70,000 y S/100,000': 2401,
  'Más de S/100,000': 2397,
  'Menos de S/15,000': 2391,
  'S/15,000 - S/25,000': 2391,
  'S/25,000 - S/50,000': 2395,
  'S/50,000 - S/100,000': 2399
};

const ingreso_raw = input.ingreso || '';
const inicial_raw = input.inicial || '';
const ingresos_id = mapaIngresos[ingreso_raw] || 2379;
const inicial_id = mapaInicial[inicial_raw] || 2391;

// ===== APROBADO / NO APROBADO =====
const esNoAprobado = ingreso_raw === 'Menos de S/3,000';
const stage_id = esNoAprobado ? 'C5:UC_GFZ3OE' : 'C5:UC_SBLKBK';

// ===== FORMATEAR TELEFONO =====
let tel = (input.telefono || '').toString().replace(/[^0-9]/g, '');
if (tel.length === 9) tel = '51' + tel;
else if (tel.startsWith('51') && tel.length === 11) { /* ya tiene 51 */ }
else if (tel.length > 11) tel = '51' + tel.slice(-9);
const telefono = '+' + tel;

// ===== SEPARAR NOMBRE =====
const nombreCompleto = (input.nombre || '').trim();
const partes = nombreCompleto.split(' ');
const nombre = partes[0] || '';
const apellido = partes.slice(1).join(' ') || '';

return {
  json: {
    nombre_completo: nombreCompleto,
    nombre,
    apellido,
    correo: input.correo || '',
    telefono,
    ingresos_id,
    inicial_id,
    stage_id,
    es_aprobado: !esNoAprobado,
    utm_source: input.utm_source || 'landing-meta',
    utm_medium: input.utm_medium || '',
    utm_campaign: input.utm_campaign || '',
    utm_content: input.utm_content || '',
    utm_term: input.utm_term || '',
    landing_url: input.landing_url || ''
  }
};

